using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Searches the web for a given query and returns a list of results with titles, URLs, and snippets.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query string")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);

        try
        {
            // Uses the DuckDuckGo Instant Answer API (no API key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            var response = await _httpClient.GetStringAsync(url);
            var doc = JsonDocument.Parse(response);
            var root = doc.RootElement;

            var results = new List<SearchResult>();

            // Extract the abstract (top result)
            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();

            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add(new SearchResult(
                    Title: abstractSource ?? "Top Result",
                    Url: abstractUrl ?? "",
                    Snippet: abstractText));
            }

            // Extract related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray())
                {
                    if (results.Count >= maxResults) break;

                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var firstUrl = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;

                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.Add(new SearchResult(
                            Title: text.Length > 80 ? text[..80] + "…" : text,
                            Url: firstUrl ?? "",
                            Snippet: text));
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No results found for '{query}'. Try rephrasing the query.";
            }

            return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
        }
        catch (HttpRequestException ex)
        {
            return $"Search failed: {ex.Message}. Please try again.";
        }
    }

    private sealed record SearchResult(string Title, string Url, string Snippet);
}

using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

public sealed class NoteTakingTool
{
    private readonly List<Note> _notes = [];

    [Description("Saves a research note with a category tag. Use this to record key findings from search results.")]
    public string SaveNote(
        [Description("The category or tag for this note (e.g., 'definition', 'history', 'key-fact')")] string category,
        [Description("The content of the note")] string content,
        [Description("The source URL, if available")] string? sourceUrl = null)
    {
        var note = new Note(
            Id: _notes.Count + 1,
            Category: category,
            Content: content,
            SourceUrl: sourceUrl,
            Timestamp: DateTime.UtcNow);

        _notes.Add(note);
        return $"Note #{note.Id} saved under '{category}'. Total notes: {_notes.Count}.";
    }

    [Description("Retrieves all saved notes, optionally filtered by category.")]
    public string GetNotes(
        [Description("Optional category to filter by. Leave empty to get all notes.")] string? category = null)
    {
        var filtered = string.IsNullOrWhiteSpace(category)
            ? _notes
            : _notes.Where(n => n.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

        if (filtered.Count == 0)
        {
            return string.IsNullOrWhiteSpace(category)
                ? "No notes saved yet."
                : $"No notes found under category '{category}'.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"--- {filtered.Count} note(s) ---");

        foreach (var note in filtered)
        {
            sb.AppendLine($"[#{note.Id}] ({note.Category}) {note.Content}");
            if (!string.IsNullOrWhiteSpace(note.SourceUrl))
                sb.AppendLine($"    Source: {note.SourceUrl}");
        }

        return sb.ToString();
    }

    private sealed record Note(int Id, string Category, string Content, string? SourceUrl, DateTime Timestamp);
}

