using System.Reflection;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// Build MEAI chat client via OpenAI provider
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// Create tool instances
var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
var searchTool = new WebSearchTool(httpClient);
var noteTool = new NoteTakingTool();

// Build AIFunction list from tool instance methods using reflection
var tools = new List<AITool>();

foreach (var method in typeof(WebSearchTool).GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
    tools.Add(AIFunctionFactory.Create(method, searchTool));

foreach (var method in typeof(NoteTakingTool).GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
    tools.Add(AIFunctionFactory.Create(method, noteTool));

var instructions = """
    You are a research agent. Your goal is to thoroughly research the given topic
    using the available tools and produce a well-organized summary.

    Follow this process:
    1. Search the web for the topic using multiple relevant queries.
    2. Save important findings as notes using categories like 'definition',
       'key-fact', 'history', 'application', or 'statistic'.
    3. After collecting enough information (at least 3-5 notes), retrieve
       all your notes and synthesize them into a clear, structured summary.

    Always cite sources when available. Be thorough but concise.
    """;

// Create the agent with tools — ChatClientAgent handles the tool-calling loop
var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 Research Agent              ║");
Console.WriteLine("║  Type a topic to research, or 'quit' ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.Write("Research topic> ");
    var topic = Console.ReadLine()?.Trim();

    if (string.IsNullOrWhiteSpace(topic))
        continue;

    if (topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine($"\nResearching: {topic}\n");

    // Create a new session per research request
    var session = await agent.CreateSessionAsync();

    var userMessage = $"Research this topic and provide a comprehensive summary: {topic}";

    // Stream the agent response — the agent handles multi-turn tool calling internally
    Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
    await foreach (var update in agent.RunStreamingAsync(userMessage, session))
    {
        if (update.Text is { } text)
        {
            Console.Write(text);
        }
    }
    Console.WriteLine();
    Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
    Console.WriteLine();
}

