using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using OpenAI;
using ResearchAgent.Tools;

var builder = Host.CreateApplicationBuilder(args);

builder.Services.AddHttpClient<WebSearchTool>();

builder.Services.AddSingleton<NoteTakingTool>();

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OpenAI API key via 'AI:ApiKey' in config or the OPENAI_API_KEY environment variable.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseLogging()
    .Use(new OpenAIClient(apiKey).GetChatClient(modelId)));

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var searchTool = host.Services.GetRequiredService<WebSearchTool>();
var noteTool = host.Services.GetRequiredService<NoteTakingTool>();
var logger = host.Services.GetRequiredService<ILoggerFactory>().CreateLogger("ResearchAgent");

// Register tools from the tool instances
var tools = new AIFunctionFactory.AIFunctionCollection();
tools.AddRange(AIFunctionFactory.Create(searchTool));
tools.AddRange(AIFunctionFactory.Create(noteTool));

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 Research Agent              ║");
Console.WriteLine("║  Type a topic to research, or 'quit' ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.Write("Research topic> ");
    var topic = Console.ReadLine()?.Trim();

    if (string.IsNullOrWhiteSpace(topic))
        continue;

    if (topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine($"\nResearching: {topic}\n");

    var systemPrompt = $"""
        You are a research agent. Your goal is to thoroughly research the given topic
        using the available tools and produce a well-organized summary.

        Follow this process:
        1. Search the web for the topic using multiple relevant queries.
        2. Save important findings as notes using categories like 'definition',
           'key-fact', 'history', 'application', or 'statistic'.
        3. After collecting enough information (at least 3-5 notes), retrieve
           all your notes and synthesize them into a clear, structured summary.

        Always cite sources when available. Be thorough but concise.
        """;

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, systemPrompt),
        new(ChatRole.User, $"Research this topic and provide a comprehensive summary: {topic}"),
    };

    var options = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
        Tools = [.. tools],
    };

    const int maxIterations = 15;
    var iteration = 0;

    // Agent loop: let the model call tools until it produces a final answer
    while (iteration++ < maxIterations)
    {
        var response = await chatClient.GetResponseAsync(messages, options);
        messages.AddMessages(response);

        // Check if the model made any tool calls
        var hasToolCalls = response.Messages
            .Any(m => m.Contents.OfType<FunctionCallContent>().Any());

        if (!hasToolCalls)
        {
            // Final response — no more tool calls
            var finalText = response.Messages
                .SelectMany(m => m.Contents.OfType<TextContent>())
                .LastOrDefault()?.Text;

            Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
            Console.WriteLine(finalText ?? "(No summary generated)");
            Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");

            logger.LogInformation(
                "Research complete. Iterations={Iterations}, Messages={MessageCount}",
                iteration, messages.Count);
            break;
        }

        // Log tool calls (non-sensitive metadata only)
        foreach (var fc in response.Messages.SelectMany(m => m.Contents.OfType<FunctionCallContent>()))
        {
            Console.WriteLine($"  🔧 Calling: {fc.Name}");
            logger.LogDebug("Tool call: {ToolName}", fc.Name);
        }
    }

    if (iteration > maxIterations)
    {
        Console.WriteLine("⚠️  Reached maximum iterations. Partial results may be available.");
    }

    Console.WriteLine();
}

